VALUES
  ('medical-tech-moex-03208', 'medical-tech', 'medical-tech-moex-113-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', 'NPM1基因的變異常出現在血液腫瘤中，其中最常見的是在第十二外顯子（exon 12）有4 bp的插入 （insertion）突變。假設野生型的序列為GCTATTCAAGATCTCTG▼GCAGTGGAGGAAGTCTCTT，▼表示突變插入處。 若以傳統的聚合酶連鎖反應配合桑格定序（Sanger sequencing），則最有可能有插入突變的定序圖為何？ A. B. C. D.', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:13+00:00", "source_pdf_sha1": "e3e83a07c05c", "answer_pdf_sha1": "40acdaaaecd6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "113", "exam_name": "113年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 59, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-03209', 'medical-tech', 'medical-tech-moex-113-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '下圖為次世代定序產出的序列比對結果，此為正股序列；若箭號處為發生基因變異的位點，則此位點產生了 那種突變？', '["T＞C", "C＞T", "A＞G", "G＞A"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:13+00:00", "source_pdf_sha1": "e3e83a07c05c", "answer_pdf_sha1": "40acdaaaecd6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "113", "exam_name": "113年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 60, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-03210', 'medical-tech', 'medical-tech-moex-113-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '承上題，此基因變異的mutant allele frequency約是多少？', '["80%", "60%", "40%", "20%"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:13+00:00", "source_pdf_sha1": "e3e83a07c05c", "answer_pdf_sha1": "40acdaaaecd6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "113", "exam_name": "113年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 61, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-03211', 'medical-tech', 'medical-tech-moex-113-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '關於評估次世代定序品質的敘述，下列何者最不適當？', '["Phred score可以用來評估鹼基的品質，常用Q值來表示", "定序深度（depth）與基因變異辨認（variant calling）的準確度無關", "定序覆蓋範圍（coverage）是指基因變異區域被定序到的次數", "生殖細胞系突變（germline mutation）的allele burden通常會接近50%"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:13+00:00", "source_pdf_sha1": "e3e83a07c05c", "answer_pdf_sha1": "40acdaaaecd6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "113", "exam_name": "113年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 62, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-03212', 'medical-tech', 'medical-tech-moex-113-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '實驗室收到四種檢體要做分子檢驗，下列何者最不適當？', '["acid citrate dextrose（ACD）當抗凝劑的全血；檢驗項目：HLA-B*1502", "以heparin當抗凝劑的血漿；檢驗項目：HBV病毒定量", "含無甲醛防腐劑（當穩定劑）的全血；檢驗項目：非侵入性胎兒染色體檢驗", "無抗凝劑的血清；檢驗項目：HCV病毒定量"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:13+00:00", "source_pdf_sha1": "e3e83a07c05c", "answer_pdf_sha1": "40acdaaaecd6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "113", "exam_name": "113年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 63, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-03213', 'medical-tech', 'medical-tech-moex-113-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '下列何者會影響臨床分子檢測的敏感度（sensitivity）？① cross contamination　② inefficient', '["①②③", "②③④", "①②④", "①③④"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:13+00:00", "source_pdf_sha1": "e3e83a07c05c", "answer_pdf_sha1": "40acdaaaecd6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "113", "exam_name": "113年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 64, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-03214', 'medical-tech', 'medical-tech-moex-113-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '關於 nucleic acid sequence-based amplification（NASBA）的敘述，下列何者最不適當？', '["此技術已被廣泛應用於RNA病毒與細菌的偵測", "可以加入寡核苷酸探針的信號分子（molecular beacon），再藉由反應後所產生之螢光訊號的強度定量 RNA，此稱為 real-time NASBA", "若檢體中有少量雙股DNA存在，會有偽陽性的結果，所以反應時需要加入DNase去除DNA", "real-time NASBA的擴增與檢測反應，全在同一密閉管內進行，可以降低核酸污染發生的可能性"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:13+00:00", "source_pdf_sha1": "e3e83a07c05c", "answer_pdf_sha1": "40acdaaaecd6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "113", "exam_name": "113年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 65, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-03215', 'medical-tech', 'medical-tech-moex-113-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '抗生素及其抗藥基因之配對，下列何者最不適當？', '["erythromycin-erm", "penicillin-mecA", "fluoroquinolone-gyrA", "lincosamide-mefA"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:13+00:00", "source_pdf_sha1": "e3e83a07c05c", "answer_pdf_sha1": "40acdaaaecd6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "113", "exam_name": "113年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 66, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-03216', 'medical-tech', 'medical-tech-moex-113-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '關於HIV的分子檢測，下列敘述何者最不適當？', '["進行定量分子檢測時，偵測的基因標的以LTR、pol、gag或int為主", "偵測嬰兒是否是先天性感染時，以PCR 檢測proviral DNA", "偵測病毒抗藥性時，是擴增血球中病毒核酸的 reverse transcriptase 與 protease 基因後定序", "常見的病毒抗藥性突變位點，包括M184V、Q151M等"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:13+00:00", "source_pdf_sha1": "e3e83a07c05c", "answer_pdf_sha1": "40acdaaaecd6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "113", "exam_name": "113年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 67, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-03217', 'medical-tech', 'medical-tech-moex-113-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '下列引發紅疹之病毒的PCR檢測，何者不需要 reverse transcription 的反應步驟？', '["measles", "mumps", "rubella", "parvovirus B19"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:13+00:00", "source_pdf_sha1": "e3e83a07c05c", "answer_pdf_sha1": "40acdaaaecd6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "113", "exam_name": "113年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 68, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL)
